class ToastManager{constructor(options={}){this.container=null;this.toasts=[];this.toastId=0;this.options={position: options.position||'top-right',duration: options.duration||5000,maxToasts: options.maxToasts||5,showClose: options.showClose!==false,showProgress: options.showProgress!==false,...options};this.init();}init(){this.container=document.querySelector('.toast-container');if(!this.container){this.container=document.createElement('div');this.container.className='toast-container';const positionClass=this.getPositionClass(this.options.position);if(positionClass){this.container.classList.add(positionClass);}document.body.appendChild(this.container);}}getPositionClass(position){const map={'top-right': '','top-left': 'toast-container--left','top-center': 'toast-container--center','bottom-right': 'toast-container--bottom','bottom-left': 'toast-container--bottom toast-container--left','bottom-center': 'toast-container--bottom toast-container--center'};return map[position]||'';}show(message,options={}){const{type='info',title=null,duration=this.options.duration,closable=this.options.showClose,showProgress=this.options.showProgress,actions=[],onClose=null,icon=null}=options;if(this.toasts.length>=this.options.maxToasts){const oldest=this.toasts.shift();this.remove(oldest.id,false);}const id=++this.toastId;const toast=document.createElement('div');toast.className=`toast toast--${type}`;toast.dataset.id=id;let iconHtml='';if(icon){iconHtml=`<span class="material-symbols-outlined">${icon}</span>`;}else{const defaultIcons={success: 'check_circle',error: 'error',warning: 'warning',info: 'info'};iconHtml=`<span class="material-symbols-outlined">${defaultIcons[type]||'info'}</span>`;}let titleHtml='';if(title){titleHtml=`<div class="toast-title">${this.escapeHtml(title)}</div>`;}let actionsHtml='';if(actions.length>0){actionsHtml='<div class="toast-actions">';actions.forEach(action=>{const btnClass=action.primary ? 'toast-action-btn--primary' : 'toast-action-btn--secondary';actionsHtml+=`<button class="toast-action-btn ${btnClass}" data-action="${action.id||''}">${this.escapeHtml(action.label)}</button>`;});actionsHtml+='</div>';}let closeHtml='';if(closable){closeHtml=`<button class="toast-close" aria-label="Close"><span class="material-symbols-outlined">close</span></button>`;}let progressHtml='';if(showProgress&&duration>0){progressHtml=`<div class="toast-progress"><div class="toast-progress__bar toast-progress__bar--animating" style="animation-duration: ${duration}ms"></div></div>`;}toast.innerHTML=`<div class="toast-icon">${iconHtml}</div><div class="toast-content">${titleHtml}<div class="toast-message">${this.escapeHtml(message)}</div>${actionsHtml}</div>${closeHtml}${progressHtml}`;const closeBtn=toast.querySelector('.toast-close');if(closeBtn){closeBtn.addEventListener('click',()=>this.remove(id,true,onClose));}const actionBtns=toast.querySelectorAll('.toast-action-btn');actionBtns.forEach(btn=>{btn.addEventListener('click',(e)=>{const actionId=e.target.dataset.action;const action=actions.find(a=>a.id===actionId);if(action&&action.onClick){action.onClick();}this.remove(id,true,onClose);});});if(duration>0){toast.dismissTimer=setTimeout(()=>{this.remove(id,true,onClose);},duration);}this.container.appendChild(toast);this.toasts.push({id,element: toast});toast.addEventListener('click',(e)=>{if(e.target===toast){this.remove(id,true,onClose);}});return id;}success(message,options={}){return this.show(message,{...options,type: 'success'});}error(message,options={}){return this.show(message,{...options,type: 'error'});}warning(message,options={}){return this.show(message,{...options,type: 'warning'});}info(message,options={}){return this.show(message,{...options,type: 'info'});}remove(id,animate=true,callback=null){const index=this.toasts.findIndex(t=>t.id===id);if(index===-1)return;const toast=this.toasts[index].element;if(toast.dismissTimer){clearTimeout(toast.dismissTimer);}if(animate){toast.classList.add('toast--exiting');toast.addEventListener('animationend',()=>{toast.remove();if(callback)callback();});}else{toast.remove();if(callback)callback();}this.toasts.splice(index,1);}clear(){[...this.toasts].forEach(t=>this.remove(t.id,true));}setPosition(position){this.container.className='toast-container';const positionClass=this.getPositionClass(position);if(positionClass){this.container.classList.add(positionClass);}}escapeHtml(text){const div=document.createElement('div');div.textContent=text;return div.innerHTML;}}window.Toast=new ToastManager();export default ToastManager;